#include "XSbench_header.cuh"

#ifdef MPI
#include<mpi.h>
#endif

int main( int argc, char* argv[] )
{

	int version = 20;
	int mype = 0;
	double omp_start, omp_end;
	int nprocs = 1;
	unsigned long long verification;

	#ifdef MPI
	MPI_Init(&argc, &argv);
	MPI_Comm_size(MPI_COMM_WORLD, &nprocs);
	MPI_Comm_rank(MPI_COMM_WORLD, &mype);
	#endif

	Inputs in = read_CLI( argc, argv );

	if( mype == 0 )
		print_inputs( in, nprocs, version );

	SimulationData SD;

	if( in.binary_mode == READ )
		SD = binary_read(in);
	else
		SD = grid_init_do_not_profile( in, mype );

	if( in.binary_mode == WRITE && mype == 0 )
		binary_write(in, SD);

	SimulationData GSD = move_simulation_data_to_device( in, mype, SD );

	if( mype == 0 )
	{
		printf("\n");
		border_print();
		center_print("SIMULATION", 79);
		border_print();
	}

	omp_start = get_time();

	if( in.simulation_method == EVENT_BASED )
	{
		if( in.kernel_id == 0 )
			verification = run_event_based_simulation_baseline(in, GSD, mype);
		else if( in.kernel_id == 1 )
			verification = run_event_based_simulation_optimization_1(in, GSD, mype);
		else if( in.kernel_id == 2 )
			verification = run_event_based_simulation_optimization_2(in, GSD, mype);
		else if( in.kernel_id == 3 )
			verification = run_event_based_simulation_optimization_3(in, GSD, mype);
		else if( in.kernel_id == 4 )
			verification = run_event_based_simulation_optimization_4(in, GSD, mype);
		else if( in.kernel_id == 5 )
			verification = run_event_based_simulation_optimization_5(in, GSD, mype);
		else if( in.kernel_id == 6 )
			verification = run_event_based_simulation_optimization_6(in, GSD, mype);
		else
		{
			printf("Error: No kernel ID %d found!\n", in.kernel_id);
			exit(1);
		}
	}
	else
	{
		printf("History-based simulation not implemented in CUDA code. Instead,\nuse the event-based method with \"-m event\" argument.\n");
		exit(1);
	}

	if( mype == 0)	
	{	
		printf("\n" );
		printf("Simulation complete.\n" );
	}

	omp_end = get_time();

	release_device_memory(GSD);

	verification = verification % 999983;

	int is_invalid_result = print_results( in, mype, omp_end-omp_start, nprocs, verification );

	#ifdef MPI
	MPI_Finalize();
	#endif

	return is_invalid_result;
}

__global__ void xs_lookup_kernel_baseline(Inputs in, SimulationData GSD )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if (i >= in.lookups) return;

	uint64_t seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, 2*i);

	double p_energy = LCG_random_double(&seed);
	int mat         = pick_mat(&seed); 

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,        
			mat,             
			in.n_isotopes,   
			in.n_gridpoints, 
			GSD.num_nucs,     
			GSD.concs,        
			GSD.unionized_energy_array, 
			GSD.index_grid,   
			GSD.nuclide_grid, 
			GSD.mats,         
			macro_xs_vector, 
			in.grid_type,    
			in.hash_bins,    
			GSD.max_num_nucs  
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	unsigned long long local_verification = max_idx + 1;

	int idx = i;
	while (idx > 0) {
		local_verification += GSD.verification[idx-1];
		idx /= 2;
	}

	if (i == 0) {
		GSD.verification[0] = local_verification;
	} else {
		GSD.verification[i] = local_verification;
	}
}

unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	
		printf("Beginning event based simulation (Baseline)...\n");

	int threads = 1024;
	int blocks = (in.lookups + threads - 1) / threads;

	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	unsigned long long verification = 0;
	cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

	return verification;
}

__global__ void sampling_kernel(Inputs in, SimulationData GSD )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if (i >= in.lookups) return;

	uint64_t seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, 2*i);

	double p_energy = LCG_random_double(&seed);
	int mat         = pick_mat(&seed); 

	GSD.p_energy_samples[i] = p_energy;
	GSD.mat_samples[i] = mat;
}

