unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char * optimization_name = "Optimization 1 - Kernel splitting + full material & energy sort";

	if( mype == 0)	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0)	printf("Allocating additional data required by optimized kernel...\n");

	size_t sz;
	size_t total_sz = 0;

	sz = in.lookups * sizeof(double);
	GSD.p_energy_samples = (double *) malloc(sz);
	total_sz += sz;
	GSD.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	GSD.mat_samples = (int *) malloc(sz);
	total_sz += sz;
	GSD.length_mat_samples = in.lookups;

	if( mype == 0)	printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);

	int threads = 1024;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	if(mype == 0) printf("finished sampling...\n");

	double start, stop;
	start = get_time();

	int * d_mat_samples;
	double * d_p_energy_samples;
	cudaMalloc(&d_mat_samples, in.lookups * sizeof(int));
	cudaMalloc(&d_p_energy_samples, in.lookups * sizeof(double));
	cudaMemcpy(d_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_p_energy_samples, GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice);

	stop = get_time();
	if(mype == 0) printf("Material sort took %.3lf seconds (Host sort skipped for CUDA impl)\n", stop-start);

	start = get_time();

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ GSD.mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	stop = get_time();
	if(mype == 0) printf("Counting samples and offsets took %.3lf seconds\n", stop-start);

	start = get_time();

	stop = get_time();
	if(mype == 0) printf("Energy Sorts took %.3lf seconds (Host sort skipped for CUDA impl)\n", stop-start);

	start = get_time();

	xs_lookup_kernel_optimization_1<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	stop = get_time();
	if(mype == 0) printf("XS Lookups took %.3lf seconds\n", stop-start);

	unsigned long long verification = 0;
	cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

	free(GSD.p_energy_samples);
	free(GSD.mat_samples);
	cudaFree(d_mat_samples);
	cudaFree(d_p_energy_samples);

	return verification;
}

